urlset:

  {{ site_url }}/
  {{ now_date }}
  hourly
  1.0


  {{ site_url }}/sources
  {{ now_date }}
  weekly
  0.6


  {{ site_url }}/about
  monthly
  0.5

{% for cat in categories %}

  {{ site_url }}/?category={{ cat | urlencode }}
  {{ now_date }}
  hourly
  0.8

{% endfor %}
{% for t in top_tags %}

  {{ site_url }}/tag/{{ t.tag | urlencode }}
  {{ now_date }}
  daily
  0.7

{% endfor %}
{% for article in articles %}

  {{ site_url }}/article/{{ article.slug or article.uid }}
  {{ article.published[:10] }}
  never
  {{ '0.9' if article.source_name == 'DeepTrendLab' else '0.7' }}
  {% if article.image_url %}

    {{ article.image_url }}

  {% endif %}

{% endfor %}
